INSERT INTO public.sentences (id,list_id,ru,ru_stressed,translit,en,pl,de,sort_order) VALUES
('orderingfood-part-1-1','orderingfood-part-1','Я хочу заказать еду.','Я хочу́ заказа́ть еду́.','Ya khochu zakazat yedu.','I want to order food.','Chcę zamówić jedzenie.','Ich möchte Essen bestellen.',1),
('orderingfood-part-1-2','orderingfood-part-1','Мы идём в ресторан.','Мы идём в рестора́н.','My idyom v restoran.','We are going to a restaurant.','Idziemy do restauracji.','Wir gehen in ein Restaurant.',2),
('orderingfood-part-1-3','orderingfood-part-1','Этот ресторан очень популярный.','Э́тот рестора́н о́чень популя́рный.','Etot restoran ochen populyarnyy.','This restaurant is very popular.','Ta restauracja jest bardzo popularna.','Dieses Restaurant ist sehr beliebt.',3),
('orderingfood-part-1-4','orderingfood-part-1','У нас есть бронь.','У нас есть бронь.','U nas yest bron.','We have a reservation.','Mamy rezerwację.','Wir haben eine Reservierung.',4),
('orderingfood-part-1-5','orderingfood-part-1','Официант показывает нам столик.','Официа́нт пока́зывает нам сто́лик.','Ofitsiant pokazyvayet nam stolik.','The waiter shows us a table.','Kelner pokazuje nam stolik.','Der Kellner zeigt uns einen Tisch.',5),
('orderingfood-part-1-6','orderingfood-part-1','Мы садимся за стол.','Мы сади́мся за стол.','My sadimsya za stol.','We sit at the table.','Siadamy przy stole.','Wir setzen uns an den Tisch.',6),
('orderingfood-part-1-7','orderingfood-part-1','Можно меню?','Мо́жно меню́?','Mozhno menyu?','Can I have the menu?','Czy mogę prosić o menu?','Kann ich die Speisekarte bekommen?',7),
('orderingfood-part-1-8','orderingfood-part-1','Я читаю меню.','Я чита́ю меню́.','Ya chitayu menyu.','I am reading the menu.','Czytam menu.','Ich lese die Speisekarte.',8),
('orderingfood-part-1-9','orderingfood-part-1','Здесь много блюд.','Здесь мно́го блюд.','Zdes mnogo blyud.','There are many dishes here.','Jest tu wiele dań.','Hier gibt es viele Gerichte.',9),
('orderingfood-part-1-10','orderingfood-part-1','Я не могу выбрать.','Я не могу́ вы́брать.','Ya ne mogu vybrat.','I cannot choose.','Nie mogę się zdecydować.','Ich kann mich nicht entscheiden.',10),
('orderingfood-part-1-11','orderingfood-part-1','Что вы рекомендуете?','Что вы рекоменду́ете?','Chto vy rekomenduyete?','What do you recommend?','Co pan/pani poleca?','Was empfehlen Sie?',11),
('orderingfood-part-1-12','orderingfood-part-1','Это блюдо очень популярно.','Э́то блю́до о́чень популя́рно.','Eto blyudo ochen populyarno.','This dish is very popular.','To danie jest bardzo popularne.','Dieses Gericht ist sehr beliebt.',12),
('orderingfood-part-1-13','orderingfood-part-1','Я возьму это.','Я возьму́ э́то.','Ya vozmu eto.','I will take that.','Wezmę to.','Ich nehme das.',13),
('orderingfood-part-1-14','orderingfood-part-1','Я хотел бы суп.','Я хоте́л бы суп.','Ya khotel by sup.','I would like a soup.','Chciałbym zupę.','Ich hätte gern eine Suppe.',14),
('orderingfood-part-1-15','orderingfood-part-1','Я хотел бы салат.','Я хоте́л бы сала́т.','Ya khotel by salat.','I would like a salad.','Chciałbym sałatkę.','Ich hätte gern einen Salat.',15),
('orderingfood-part-1-16','orderingfood-part-1','Я хотел бы основное блюдо.','Я хоте́л бы основно́е блю́до.','Ya khotel by osnovnoye blyudo.','I would like a main course.','Chciałbym danie główne.','Ich hätte gern ein Hauptgericht.',16),
('orderingfood-part-1-17','orderingfood-part-1','Что входит в это блюдо?','Что вхо́дит в э́то блю́до?','Chto vkhodit v eto blyudo?','What is in this dish?','Co wchodzi w skład tego dania?','Was ist in diesem Gericht enthalten?',17),
('orderingfood-part-1-18','orderingfood-part-1','Оно содержит курицу.','Оно́ соде́ржит ку́рицу.','Ono soderzhit kuritsu.','It contains chicken.','Zawiera kurczaka.','Es enthält Hähnchen.',18),
('orderingfood-part-1-19','orderingfood-part-1','Я не ем мясо.','Я не ем мя́со.','Ya ne yem myaso.','I do not eat meat.','Nie jem mięsa.','Ich esse kein Fleisch.',19),
('orderingfood-part-1-20','orderingfood-part-1','У вас есть вегетарианские блюда?','У вас есть вегетариа́нские блю́да?','U vas yest vegetarianskiye blyuda?','Do you have vegetarian dishes?','Czy macie dania wegetariańskie?','Haben Sie vegetarische Gerichte?',20),
('orderingfood-part-1-21','orderingfood-part-1','Я хотел бы заказать напиток.','Я хоте́л бы заказа́ть напи́ток.','Ya khotel by zakazat napitok.','I would like to order a drink.','Chciałbym zamówić napój.','Ich möchte ein Getränk bestellen.',21),
('orderingfood-part-1-22','orderingfood-part-1','Можно стакан воды?','Мо́жно стака́н воды́?','Mozhno stakan vody?','Can I have a glass of water?','Czy mogę prosić o szklankę wody?','Kann ich ein Glas Wasser bekommen?',22),
('orderingfood-part-1-23','orderingfood-part-1','Я возьму минеральную воду.','Я возьму́ минера́льную во́ду.','Ya vozmu mineralnuyu vodu.','I will take mineral water.','Wezmę wodę mineralną.','Ich nehme Mineralwasser.',23),
('orderingfood-part-1-24','orderingfood-part-1','Я хотел бы чай.','Я хоте́л бы чай.','Ya khotel by chay.','I would like tea.','Chciałbym herbatę.','Ich hätte gern Tee.',24),
('orderingfood-part-1-25','orderingfood-part-1','Я хотел бы кофе.','Я хоте́л бы ко́фе.','Ya khotel by kofe.','I would like coffee.','Chciałbym kawę.','Ich hätte gern Kaffee.',25),
('orderingfood-part-1-26','orderingfood-part-1','Какой сок у вас есть?','Како́й сок у вас есть?','Kakoy sok u vas yest?','What juice do you have?','Jakie macie soki?','Welche Säfte haben Sie?',26),
('orderingfood-part-1-27','orderingfood-part-1','У нас есть яблочный сок.','У нас есть я́блочный сок.','U nas yest yablochnyy sok.','We have apple juice.','Mamy sok jabłkowy.','Wir haben Apfelsaft.',27),
('orderingfood-part-1-28','orderingfood-part-1','Я закажу яблочный сок.','Я закажу́ я́блочный сок.','Ya zakazhu yablochnyy sok.','I will order apple juice.','Zamówię sok jabłkowy.','Ich bestelle Apfelsaft.',28),
('orderingfood-part-1-29','orderingfood-part-1','Вы готовы сделать заказ?','Вы гото́вы сде́лать зака́з?','Vy gotovy sdelat zakaz?','Are you ready to order?','Czy są państwo gotowi zamówić?','Sind Sie bereit zu bestellen?',29),
('orderingfood-part-1-30','orderingfood-part-1','Да, мы готовы.','Да, мы гото́вы.','Da, my gotovy.','Yes, we are ready.','Tak, jesteśmy gotowi.','Ja, wir sind bereit.',30),
('orderingfood-part-1-31','orderingfood-part-1','Я возьму суп и салат.','Я возьму́ суп и сала́т.','Ya vozmu sup i salat.','I will take soup and salad.','Wezmę zupę i sałatkę.','Ich nehme Suppe und Salat.',31),
('orderingfood-part-1-32','orderingfood-part-1','Мой друг закажет рыбу.','Мой друг зака́жет ры́бу.','Moy drug zakazhet rybu.','My friend will order fish.','Mój przyjaciel zamówi rybę.','Mein Freund bestellt Fisch.',32),
('orderingfood-part-1-33','orderingfood-part-1','Мы ждём наш заказ.','Мы ждём наш зака́з.','My zhdyom nash zakaz.','We are waiting for our order.','Czekamy na nasze zamówienie.','Wir warten auf unsere Bestellung.',33),
('orderingfood-part-1-34','orderingfood-part-1','Еда выглядит отлично.','Еда́ вы́глядит отли́чно.','Yeda vyglyadit otlichno.','The food looks great.','Jedzenie wygląda świetnie.','Das Essen sieht großartig aus.',34),
('orderingfood-part-1-35','orderingfood-part-1','Суп очень горячий.','Суп о́чень горя́чий.','Sup ochen goryachiy.','The soup is very hot.','Zupa jest bardzo gorąca.','Die Suppe ist sehr heiß.',35),
('orderingfood-part-1-36','orderingfood-part-1','Салат очень свежий.','Сала́т о́чень све́жий.','Salat ochen svezhiy.','The salad is very fresh.','Sałatka jest bardzo świeża.','Der Salat ist sehr frisch.',36),
('orderingfood-part-1-37','orderingfood-part-1','Это блюдо очень вкусное.','Э́то блю́до о́чень вку́сное.','Eto blyudo ochen vkusnoye.','This dish is very tasty.','To danie jest bardzo smaczne.','Dieses Gericht ist sehr lecker.',37),
('orderingfood-part-1-38','orderingfood-part-1','Мне очень нравится этот вкус.','Мне о́чень нра́вится э́тот вкус.','Mne ochen nravitsya etot vkus.','I really like this taste.','Bardzo podoba mi się ten smak.','Dieser Geschmack gefällt mir sehr.',38),
('orderingfood-part-1-39','orderingfood-part-1','Мы едим медленно.','Мы еди́м ме́дленно.','My yedim medlenno.','We eat slowly.','Jemy powoli.','Wir essen langsam.',39),
('orderingfood-part-1-40','orderingfood-part-1','Мы наслаждаемся едой.','Мы наслажда́емся едо́й.','My naslazhdayemsya yedoy.','We enjoy the food.','Cieszymy się jedzeniem.','Wir genießen das Essen.',40),
('orderingfood-part-1-41','orderingfood-part-1','Можно ещё хлеба?','Мо́жно ещё хле́ба?','Mozhno eshchyo khleba?','Can I have some more bread?','Czy mogę prosić o więcej chleba?','Kann ich noch etwas Brot bekommen?',41),
('orderingfood-part-1-42','orderingfood-part-1','Конечно, сейчас принесу.','Коне́чно, сейча́с принесу́.','Konechno, seychas prinesu.','Of course, I will bring it right away.','Oczywiście, zaraz przyniosę.','Natürlich, ich bringe es sofort.',42),
('orderingfood-part-1-43','orderingfood-part-1','Вы хотите десерт?','Вы хоти́те десе́рт?','Vy khotite desert?','Would you like dessert?','Czy chcą państwo deser?','Möchten Sie ein Dessert?',43),
('orderingfood-part-1-44','orderingfood-part-1','Да, я хотел бы торт.','Да, я хоте́л бы торт.','Da, ya khotel by tort.','Yes, I would like cake.','Tak, chciałbym ciasto.','Ja, ich hätte gern Kuchen.',44),
('orderingfood-part-1-45','orderingfood-part-1','У вас есть мороженое?','У вас есть моро́женое?','U vas yest morozhenoye?','Do you have ice cream?','Czy macie lody?','Haben Sie Eis?',45),
('orderingfood-part-1-46','orderingfood-part-1','Я возьму шоколадное мороженое.','Я возьму́ шокола́дное моро́женое.','Ya vozmu shokoladnoye morozhenoye.','I will take chocolate ice cream.','Wezmę lody czekoladowe.','Ich nehme Schokoladeneis.',46),
('orderingfood-part-1-47','orderingfood-part-1','Десерт был великолепным.','Десе́рт был великоле́пным.','Desert byl velikolepnym.','The dessert was excellent.','Deser był wspaniały.','Das Dessert war ausgezeichnet.',47),
('orderingfood-part-1-48','orderingfood-part-1','Можно счёт, пожалуйста?','Мо́жно счёт, пожа́луйста?','Mozhno schyot, pozhaluysta?','Can I have the bill, please?','Czy mogę prosić o rachunek?','Kann ich bitte die Rechnung bekommen?',48),
('orderingfood-part-1-49','orderingfood-part-1','Я заплачу картой.','Я заплачу́ ка́ртой.','Ya zaplachu kartoy.','I will pay by card.','Zapłacę kartą.','Ich zahle mit Karte.',49),
('orderingfood-part-1-50','orderingfood-part-1','Спасибо, всё было прекрасно.','Спаси́бо, всё бы́ло прекра́сно.','Spasibo, vsyo bylo prekrasno.','Thank you, everything was wonderful.','Dziękuję, wszystko było wspaniałe.','Danke, alles war wunderbar.',50)
